interviewQuestions.answer:
Currying allows you to partially apply functions to create single-argument functions that can be composed with pipe/compose: <code>const add1 = curry(add)(1);
const double = curry(multiply)(2);
const add1ThenDouble = pipe(add1, double);
add1ThenDouble(5); // 12</code> Each curried function returns a unary function suitable for composition.

Lodash/fp and Ramda use currying extensively. For example, in Ramda: <code>const add1 = R.add(1); // curried, returns function
const double = R.multiply(2);
const result = R.pipe(add1, double)(5); // 12
R.map(add1, [1, 2, 3]); // [2, 3, 4]
R.map(add1)([1, 2, 3]); // same (curried)</code> In Redux, selectors can be curried: <code>const selectItems = (state) => state.items;
const selectItemById = (id) => (state) => state.items[id];</code>

codeExamples.code:
// Uncurried version
function add(a, b, c) {
  return a + b + c;
}

// Manually curried version
function curriedAdd(a) {
  return function(b) {
    return function(c) {
      return a + b + c;
    };
  };
}

console.log(add(1, 2, 3));           // 6
console.log(curriedAdd(1)(2)(3));    // 6

// Partial application in action:
const add1 = curriedAdd(1);    // returns function(b) with a=1
const add1And2 = add1(2);      // returns function(c) with a=1, b=2
console.log(add1And2(3));      // 6

function curry(fn) {
  return function curried(...args) {
    if (args.length >= fn.length) {
      return fn.apply(this, args);
    }
    return function(...nextArgs) {
      return curried.apply(this, args.concat(nextArgs));
    };
  };
}

const sum = (a, b, c) => a + b + c;
const curriedSum = curry(sum);

console.log(curriedSum(1)(2)(3));       // 6
console.log(curriedSum(1, 2)(3));       // 6
console.log(curriedSum(1)(2, 3));       // 6
console.log(curriedSum(1, 2, 3));       // 6

// Also works for different arities:
const greet = (greeting, name) => `${greeting}, ${name}!`;
const curriedGreet = curry(greet);
const sayHello = curriedGreet('Hello');
console.log(sayHello('World')); // 'Hello, World!'

const fetchWith = curry(
  (baseUrl, endpoint, options) =>
    fetch(`${baseUrl}${endpoint}`, options)
      .then(res => res.json())
);

// Create a pre-configured API client
const api = fetchWith('https://api.example.com');

// Get specific endpoints
const getUsers = api('/users');
const getPosts = api('/posts');

// Use them
const users = await getUsers({ headers: { 'Auth': 'token' } });
const posts = await getPosts({ headers: { 'Auth': 'token' } });

// Or pre-configure authentication too
const authenticatedApi = api.withAuth = 
  curry(fetchWith)('https://api.example.com')('/users');
// Then: const users = await authenticatedApi({ headers: authHeaders });

// Utility functions
const add = curry((a, b) => a + b);
const multiply = curry((a, b) => a * b);
const map = curry((fn, arr) => arr.map(fn));
const filter = curry((fn, arr) => arr.filter(fn));

// Pre-configure operations
const add1 = add(1);
const double = multiply(2);
const isEven = x => x % 2 === 0;

// Compose pipeline
const processNumbers = pipe(
  filter(isEven),
  map(add1),
  map(double)
);

console.log(processNumbers([1, 2, 3, 4, 5]));
// filter even: [2, 4]
// add1: [3, 5]
// double: [6, 10]
// Result: [6, 10]

// Lodash-style curry with placeholder
function curryWithPlaceholder(fn) {
  const _ = curryWithPlaceholder._ = Symbol('placeholder');

  return function curried(...args) {
    const filled = args.filter(a => a !== _).length;
    if (filled >= fn.length && args.length >= fn.length) {
      // Replace placeholders with actual args from
      // previous calls — simplified for clarity
      return fn.apply(this, args);
    }
    return function(...nextArgs) {
      const merged = args.map(a => a === _ && nextArgs.length ? nextArgs.shift() : a);
      return curried.apply(this, merged.concat(nextArgs));
    };
  };
}

// Usage:
const _ = curryWithPlaceholder._;
const greet3 = (a, b, c) => `${a} ${b} ${c}`;
const curriedG = curryWithPlaceholder(greet3);

// Skip the first argument, fill later
const withExclamation = curriedG(_, _, '!');
console.log(withExclamation('Hello', 'World')); // 'Hello World !'
// (Simplified — real placeholder curry is more complex)
